import numpy as np
from typing import List, Tuple


def cosine_similarity(a: np.ndarray, b: np.ndarray) -> float:
    """Compute cosine similarity between two vectors.
    Returns 0.0 if either vector has zero norm.
    """
    norm_a = np.linalg.norm(a)
    norm_b = np.linalg.norm(b)
    if norm_a == 0.0 or norm_b == 0.0:
        return 0.0
    return float(np.dot(a, b) / (norm_a * norm_b))


class MiniVectorStore:
    """A minimal in-memory vector store."""

    def __init__(self, dim: int):
        """Initialize the store with a given embedding dimension."""
        self.dim = dim
        self.doc_ids: List[str] = []
        self.vectors: List[np.ndarray] = []

    def add(self, doc_id: str, vector: np.ndarray) -> None:
        """Add a document embedding to the store."""
        assert vector.shape == (self.dim,), f"Expected dim {self.dim}, got {vector.shape}"
        self.doc_ids.append(doc_id)
        self.vectors.append(vector)

    def search(self, query: np.ndarray, k: int = 3) -> List[Tuple[str, float]]:
        """Return top-k most similar (doc_id, score) tuples."""
        if len(self.vectors) == 0:
            return []
        similarities = [
            (doc_id, cosine_similarity(query, vec))
            for doc_id, vec in zip(self.doc_ids, self.vectors)
        ]
        similarities.sort(key=lambda x: x[1], reverse=True)
        return similarities[:k]

    def __len__(self) -> int:
        """Return number of stored documents."""
        return len(self.doc_ids)

import math
from typing import List, Set, Tuple


def precision_at_k(retrieved: List[str], relevant: Set[str], k: int) -> float:
    """Compute Precision@k."""
    top_k = retrieved[:k]
    hits = sum(1 for doc in top_k if doc in relevant)
    return hits / k


def recall_at_k(retrieved: List[str], relevant: Set[str], k: int) -> float:
    """Compute Recall@k. Return 0.0 if relevant set is empty."""
    if len(relevant) == 0:
        return 0.0
    top_k = retrieved[:k]
    hits = sum(1 for doc in top_k if doc in relevant)
    return hits / len(relevant)


def mean_reciprocal_rank(
    results_list: List[Tuple[List[str], Set[str]]]
) -> float:
    """Compute MRR over a list of (retrieved, relevant) tuples."""
    if len(results_list) == 0:
        return 0.0
    reciprocal_ranks = []
    for retrieved, relevant in results_list:
        rr = 0.0
        for rank, doc in enumerate(retrieved, 1):
            if doc in relevant:
                rr = 1.0 / rank
                break
        reciprocal_ranks.append(rr)
    return sum(reciprocal_ranks) / len(reciprocal_ranks)


def ndcg_at_k(relevance_scores: List[float], k: int) -> float:
    """Compute NDCG@k given relevance scores in retrieval order.
    Return 0.0 if IDCG is 0."""
    scores = relevance_scores[:k]

    # DCG
    dcg = sum(
        score / math.log2(i + 2) for i, score in enumerate(scores)
    )

    # IDCG: sort all scores descending, take top k
    ideal_scores = sorted(relevance_scores, reverse=True)[:k]
    idcg = sum(
        score / math.log2(i + 2) for i, score in enumerate(ideal_scores)
    )

    if idcg == 0:
        return 0.0
    return dcg / idcg

