import numpy as np
from typing import List, Dict
from collections import Counter


class NaiveRAGPipeline:
    """A complete naive RAG pipeline with indexing, retrieval, and generation."""

    def __init__(self):
        self.documents: List[Dict] = []
        self.vocabulary: List[str] = []
        self.vocab_index: Dict[str, int] = {}
        self.embeddings: List[np.ndarray] = []

    def _tokenize(self, text: str) -> List[str]:
        """Simple whitespace tokenizer with lowercasing."""
        return text.lower().split()

    def _compute_embedding(self, text: str) -> np.ndarray:
        """Compute a normalized TF embedding using the stored vocabulary."""
        tokens = self._tokenize(text)
        counts = Counter(tokens)
        total = len(tokens) if tokens else 1

        embedding = np.zeros(len(self.vocabulary), dtype=np.float64)
        for token, count in counts.items():
            if token in self.vocab_index:
                embedding[self.vocab_index[token]] = count / total

        # L2 normalize
        norm = np.linalg.norm(embedding)
        if norm > 0:
            embedding = embedding / norm

        return embedding

    def index_documents(self, documents: List[Dict]) -> None:
        """Index documents: build vocabulary, compute and store embeddings."""
        self.documents = documents

        # Build vocabulary from all documents
        all_tokens = set()
        for doc in documents:
            tokens = self._tokenize(doc["text"])
            all_tokens.update(tokens)

        self.vocabulary = sorted(all_tokens)
        self.vocab_index = {word: i for i, word in enumerate(self.vocabulary)}

        # Compute embeddings for all documents
        self.embeddings = [
            self._compute_embedding(doc["text"]) for doc in documents
        ]

    def retrieve(self, query: str, k: int = 3) -> List[Dict]:
        """Retrieve top-k documents by cosine similarity to query."""
        query_emb = self._compute_embedding(query)

        scored = []
        for i, doc_emb in enumerate(self.embeddings):
            # Cosine similarity (embeddings are already normalized)
            sim = float(np.dot(query_emb, doc_emb))
            scored.append({
                "id": self.documents[i]["id"],
                "text": self.documents[i]["text"],
                "score": sim,
            })

        scored.sort(key=lambda x: x["score"], reverse=True)
        return scored[:k]

    def generate(self, query: str, context_docs: List[Dict]) -> str:
        """Simulate LLM generation from retrieved context."""
        excerpts = [doc["text"][:100] for doc in context_docs]
        return f"Based on {len(context_docs)} retrieved documents: " + " | ".join(excerpts)

    def query(self, question: str, k: int = 3) -> Dict:
        """Full RAG pipeline: retrieve then generate."""
        context_docs = self.retrieve(question, k=k)
        answer = self.generate(question, context_docs)
        return {
            "answer": answer,
            "sources": [doc["id"] for doc in context_docs],
            "num_sources": len(context_docs),
        }
